//#region src/utils/asyncIterable.ts
async function* mapAsyncIterable(f, source) {
	let index = 0;
	for await (const item of source) yield await f(item, index++);
}
async function* filterAsyncIterable(f, source) {
	for await (const item of source) if (await f(item)) yield item;
}

